const inp = $input.first().json;
const html = inp.html || '';
const course_id = inp.course_id || '';
const source_language = inp.source_language || 'fr';

// 1. Extraire toutes les URLs user.oc-static.com
const allUrls = [...new Set(
  (html.match(/https?:\/\/user\.oc-static\.com\/[^\s"'<>\)]+/g) || [])
)];

// 2. Filtrer : garder seulement les images (PNG, JPG, JPEG, GIF, WEBP, SVG)
const imageExts = /\.(png|jpg|jpeg|gif|webp|svg)(\?[^"'\s]*)?$/i;
const imageUrls = allUrls.filter(u => imageExts.test(u));

// 3. Exclure les banners
// Patterns OC banners : "banner" dans l'URL, "/covers/", "/backgrounds/", 
// ou images très larges (pattern _NNNNx dans le nom de fichier où NNNN >= 800)
const bannerPatterns = [
  /banner/i,
  /\/covers\//i,
  /\/backgrounds?\//i,
  /\/header/i,
  /_\d{4,}x/i,  // ex: _1200x, _1280x
  /hero/i
];
const isBanner = url => bannerPatterns.some(p => p.test(url));
const filtered = imageUrls.filter(u => !isBanner(u));

// 4. Enrichir avec métadonnées
const assets = filtered.map((url, i) => {
  const filename = url.split('/').pop().split('?')[0];
  const extMatch = filename.match(/\.(\w+)$/i);
  const ext = extMatch ? extMatch[1].toLowerCase() : 'unknown';

  // Détecter le type d'image (heuristique sur le contexte HTML)
  const urlContext = html.substring(
    Math.max(0, html.indexOf(url) - 200),
    html.indexOf(url) + url.length + 200
  );
  let image_type = 'unknown';
  if (/code|snippet|terminal|console/i.test(urlContext)) image_type = 'code_snippet';
  else if (/schema|diagram|architecture|flow/i.test(urlContext)) image_type = 'diagram';
  else if (/tableau|table|spreadsheet/i.test(urlContext)) image_type = 'table';
  else if (/screenshot|capture|interface|ui\b/i.test(urlContext)) image_type = 'ui_screenshot';
  else if (/logo/i.test(urlContext)) image_type = 'logo';
  else image_type = 'static_graphic';

  return {
    index: i + 1,
    url,
    filename,
    ext,
    image_type,
    needs_localization: source_language !== 'en' // FR→EN = besoin de localisation
  };
});

return [{
  json: {
    course_id,
    source_language,
    total_images: allUrls.length,
    total_after_filter: filtered.length,
    excluded_banners: imageUrls.length - filtered.length,
    assets,
    extracted_at: new Date().toISOString()
  }
}];
